{
  "name": "pianoquest-live",
  "version": "1.3.1",
  "description": "PianoQuest Live — interactive musical storytelling with real-time piano coaching",
  "main": "dist/index.js",
  "scripts": {
    "build": "tsc",
    "start": "node dist/index.js",
    "dev": "tsc --watch"
  },
  "dependencies": {
    "@google/adk": "^0.5.0",
    "@google/genai": "^1.37.0",
    "dotenv": "^16.4.0",
    "express": "^4.21.0",
    "ws": "^8.18.0",
    "zod": "^3.25.0"
  },
  "devDependencies": {
    "@types/express": "^4.17.21",
    "@types/node": "^22.0.0",
    "@types/ws": "^8.5.0",
    "typescript": "^5.7.0"
  }
}

