  1→/**
  2→ * PianoQuest Live — Express + WebSocket server with @google/genai Live API.
  3→ *
  4→ * ADK TS v0.5 does not have runLive() — we use the @google/genai Live API
  5→ * directly with manual tool execution. The genai Live API is callback-based:
  6→ * we pass an `onmessage` callback to `client.live.connect()`.
  7→ */
  8→
  9→import express from "express";
 10→import { createServer } from "http";
 11→import path from "path";
 12→import { WebSocketServer, WebSocket } from "ws";
 13→import { GoogleGenAI } from "@google/genai";
 14→import type { IncomingMessage } from "http";
 15→import {
 16→  LIVE_MODEL,
 17→  STORYTELLER_INSTRUCTION,
 18→  buildToolDeclarations,
 19→  executeToolLocally,
 20→  toolCallToVisualEvent,
 21→} from "./agent.js";
 22→
 23→const APP_NAME = "pianoquest";
 24→const STATIC_DIR = path.join(__dirname, "..", "..", "static");
 25→
 26→const NOTE_NAMES = ["C", "C#", "D", "D#", "E", "F", "F#", "G", "G#", "A", "A#", "B"];
 27→
 28→function midiNoteName(note: number): string {
 29→  const octave = Math.floor(note / 12) - 1;
 30→  return `${NOTE_NAMES[note % 12]}${octave}`;
 31→}
 32→
 33→function describeMidiSnapshot(
 34→  msg: Record<string, unknown>,
 35→  cameraEnabled: boolean,
 36→  bothHandsDetected: boolean,
 37→  detectedHandCount: number
 38→): string | null {
 39→  const recentNotes = (msg.recent_notes as Array<Record<string, unknown>>) ?? [];
 40→  const activeNotes = (msg.active_notes as Array<Record<string, unknown>>) ?? [];
 41→  const detectedTechniques = (msg.detected_techniques as unknown[]) ?? [];
 42→  const pedalDown = Boolean(msg.pedal_down);
 43→  const bpm = msg.bpm as number | undefined;
 44→  const score = msg.score as number | undefined;
 45→
 46→  const noteBits: string[] = [];
 47→  for (const item of recentNotes.slice(0, 8)) {
 48→    const note = item.note as number | undefined;
 49→    const velocity = item.velocity as number | undefined;
 50→    if (typeof note === "number") {
 51→      noteBits.push(
 52→        typeof velocity === "number"
 53→          ? `${midiNoteName(note)}@${velocity}`
 54→          : midiNoteName(note)
 55→      );
 56→    }
 57→  }
 58→
 59→  const activeBits: string[] = [];
 60→  for (const item of activeNotes.slice(0, 8)) {
 61→    const note = item.note as number | undefined;
 62→    const velocity = item.velocity as number | undefined;
 63→    if (typeof note === "number") {
 64→      activeBits.push(
 65→        typeof velocity === "number"
 66→          ? `${midiNoteName(note)}@${velocity}`
 67→          : midiNoteName(note)
 68→      );
 69→    }
 70→  }
 71→
 72→  const hasPerformanceSignal = recentNotes.length > 0 || activeNotes.length > 0 || pedalDown;
 73→  if (!hasPerformanceSignal) return null;
 74→
 75→  const details: string[] = [];
 76→  if (noteBits.length > 0) details.push("recent notes: " + noteBits.join(", "));
 77→  if (activeBits.length > 0) details.push("currently held: " + activeBits.join(", "));
 78→  details.push(pedalDown ? "sustain pedal is down" : "sustain pedal is up");
 79→  if (bpm) details.push(`target tempo ${bpm} BPM`);
 80→  if (score !== undefined) details.push(`current technique score ${score}`);
 81→  if (detectedTechniques.length > 0) {
 82→    details.push(
 83→      "detected techniques: " + detectedTechniques.slice(0, 6).map(String).join(", ")
 84→    );
 85→  }
 86→
 87→  if (details.length === 0) return null;
 88→
 89→  const visionState = !cameraEnabled
 90→    ? "Camera is off; do not claim visual observations."
 91→    : bothHandsDetected
 92→      ? "Both hands are visible; finger-specific visual coaching is allowed if it matches the MIDI evidence."
 93→      : `Both hands are not fully visible (detected hands: ${detectedHandCount}); do not claim finger-specific visual observations.`;
 94→
 95→  return (
 96→    "MIDI performance update from the digital piano. " +
 97→    details.join(". ") +
 98→    ". " +
 99→    visionState +
100→    " Use this instead of piano microphone audio for note, timing, and dynamics analysis."
101→  );
102→}
103→
104→// =========================================================================
105→// Spectator broadcasting — spectators receive all output but send nothing
106→// =========================================================================
107→
108→const spectators = new Set<WebSocket>();
109→
110→function broadcast(data: Buffer | string, binary = false) {
111→  for (const s of spectators) {
112→    if (s.readyState === WebSocket.OPEN) {
113→      try { s.send(data, { binary }); } catch {}
114→    }
115→  }
116→}
117→
118→// =========================================================================
119→// Room-based session sharing — remote camera sends frames to primary session
120→// =========================================================================
121→
122→interface RoomSession {
123→  sendRealtimeInput: (input: any) => void;
124→  sendClientContent: (content: any) => void;
125→  primaryWs: WebSocket;
126→  /** Accumulated MIDI notes for periodic Gemini snapshots */
127→  midiBuffer: Array<{ note: number; velocity: number; event: string; timestampMs: number }>;
128→  midiFlushTimer: ReturnType<typeof setTimeout> | null;
129→  cameraEnabled: boolean;
130→  bothHandsDetected: boolean;
131→  detectedHandCount: number;
132→}
133→
134→const rooms = new Map<string, RoomSession>();
135→
136→function generateRoomCode(): string {
137→  const chars = "REDACTED";
138→  let code = "";
139→  const arr = new Uint8Array(4);
140→  require("crypto").randomFillSync(arr);
141→  for (let i = 0; i < 4; i++) {
142→    code += chars[arr[i] % chars.length];
143→  }
144→  return code;
145→}
146→
147→// =========================================================================
148→// Express + WebSocket server
149→// =========================================================================
150→
151→export function createApp() {
152→  const app = express();
153→  const server = createServer(app);
154→  const wssDialog = new WebSocketServer({ noServer: true });
155→  const wssSpectator = new WebSocketServer({ noServer: true });
156→  const wssCamera = new WebSocketServer({ noServer: true });
157→  const wssMidi = new WebSocketServer({ noServer: true });
158→
159→  app.get("/health", (_req, res) => {
160→    res.json({
161→      status: "ok",
162→      service: APP_NAME,
163→      modes: ["storyteller"],
164→      spectators: spectators.size,
165→      rooms: rooms.size,
166→    });
167→  });
168→
169→  app.get("/", (_req, res) => {
170→    res.sendFile(path.join(STATIC_DIR, "index.html"));
171→  });
172→
173→  app.use("/static", express.static(STATIC_DIR));
174→
175→  server.on("upgrade", (request: IncomingMessage, socket, head) => {
176→    const url = new URL(request.url ?? "/", `http://${request.headers.host}`);
177→    if (url.pathname === "/ws/dialog") {
178→      wssDialog.handleUpgrade(request, socket, head, (ws) => {
179→        wssDialog.emit("connection", ws, request);
180→      });
181→    } else if (url.pathname === "/ws/spectator") {
182→      wssSpectator.handleUpgrade(request, socket, head, (ws) => {
183→        wssSpectator.emit("connection", ws, request);
184→      });
185→    } else if (url.pathname === "/ws/camera") {
186→      const room = url.searchParams.get("room") ?? "";
187→      wssCamera.handleUpgrade(request, socket, head, (ws) => {
188→        (ws as any)._room = room;
189→        wssCamera.emit("connection", ws, request);
190→      });
191→    } else if (url.pathname === "/ws/midi") {
192→      const room = url.searchParams.get("room") ?? "";
193→      wssMidi.handleUpgrade(request, socket, head, (ws) => {
194→        (ws as any)._room = room;
195→        wssMidi.emit("connection", ws, request);
196→      });
197→    } else {
198→      socket.destroy();
199→    }
200→  });
201→
202→  wssDialog.on("connection", (ws: WebSocket) => {
203→    handleWebSocket(ws);
204→  });
205→
206→  wssSpectator.on("connection", (ws: WebSocket) => {
207→    console.log(`[${APP_NAME}] Spectator connected (total: ${spectators.size + 1})`);
208→    spectators.add(ws);
209→    ws.on("close", () => {
210→      spectators.delete(ws);
211→      console.log(`[${APP_NAME}] Spectator disconnected (total: ${spectators.size})`);
212→    });
213→    ws.on("error", () => {
214→      spectators.delete(ws);
215→    });
216→  });
217→
218→  wssCamera.on("connection", (ws: WebSocket) => {
219→    const room = (ws as any)._room as string;
220→    const session = rooms.get(room);
221→    if (!session) {
222→      console.log(`[${APP_NAME}] Camera rejected — room "${room}" not found`);
223→      ws.send(JSON.stringify({ type: "error", message: `Room "${room}" not found` }));
224→      ws.close();
225→      return;
226→    }
227→
228→    console.log(`[${APP_NAME}] Remote camera connected to room "${room}"`);
229→    ws.send(JSON.stringify({ type: "camera_connected", room }));
230→
231→    ws.on("message", (data: Buffer | string) => {
232→      if (typeof data === "string") {
233→        try {
234→          const msg = JSON.parse(data);
235→          if (msg.type === "video_frame" && msg.data) {
236→            const frameBytes = Buffer.from(msg.data, "base64");
237→            session.sendRealtimeInput({
238→              media: {
239→                data: frameBytes.toString("base64"),
240→                mimeType: "image/jpeg",
241→              },
242→            });
243→          }
244→        } catch {}
245→      }
246→    });
247→
248→    ws.on("close", () => {
249→      console.log(`[${APP_NAME}] Remote camera disconnected from room "${room}"`);
250→    });
251→  });
252→
253→  // -----------------------------------------------------------------
254→  // /ws/midi — Ubuntu bridge forwards MIDI events to Gemini + iPad
255→  // -----------------------------------------------------------------
256→
257→  function flushMidiToGemini(roomSession: RoomSession) {
258→    if (roomSession.midiBuffer.length === 0) return;
259→
260→    const recentNotes = roomSession.midiBuffer
261→      .filter((m) => m.event === "noteOn")
262→      .slice(-8)
263→      .map((m) => ({ note: m.note, velocity: m.velocity }));
264→
265→    const activeNotes: Array<{ note: number; velocity: number }> = [];
266→    const noteOnMap = new Map<number, number>();
267→    for (const m of roomSession.midiBuffer) {
268→      if (m.event === "noteOn") {
269→        noteOnMap.set(m.note, m.velocity);
270→      } else if (m.event === "noteOff") {
271→        noteOnMap.delete(m.note);
272→      }
273→    }
274→    for (const [note, velocity] of noteOnMap) {
275→      activeNotes.push({ note, velocity });
276→    }
277→
278→    const summary = describeMidiSnapshot(
279→      { recent_notes: recentNotes, active_notes: activeNotes, pedal_down: false },
280→      roomSession.cameraEnabled,
281→      roomSession.bothHandsDetected,
282→      roomSession.detectedHandCount
283→    );
284→
285→    if (summary) {
286→      roomSession.sendClientContent({
287→        turns: { role: "user", parts: [{ text: summary }] },
288→        turnComplete: true,
289→      });
290→    }
291→
292→    roomSession.midiBuffer = [];
293→  }
294→
295→  wssMidi.on("connection", (ws: WebSocket) => {
296→    const room = (ws as any)._room as string;
297→    const roomSession = rooms.get(room);
298→    if (!roomSession) {
299→      console.log(`[${APP_NAME}] MIDI rejected — room "${room}" not found`);
300→      ws.send(JSON.stringify({ type: "error", message: `Room "${room}" not found` }));
301→      ws.close();
302→      return;
303→    }
304→
305→    console.log(`[${APP_NAME}] MIDI bridge connected to room "${room}"`);
306→    ws.send(JSON.stringify({ type: "midi_connected", room }));
307→
308→    ws.on("message", (data: Buffer | string) => {
309→      if (typeof data !== "string") return;
310→      try {
311→        const msg = JSON.parse(data);
312→        if (msg.type !== "midi") return;
313→
314→        // Forward raw MIDI event to iPad for waterfall rendering
315→        if (roomSession.primaryWs.readyState === WebSocket.OPEN) {
316→          roomSession.primaryWs.send(JSON.stringify(msg));
317→        }
318→        // Also broadcast to spectators
319→        broadcast(JSON.stringify(msg));
320→
321→        // Buffer for Gemini (flush every 2 seconds)
322→        if (msg.event === "noteOn" || msg.event === "noteOff") {
323→          roomSession.midiBuffer.push({
324→            note: msg.note ?? 0,
325→            velocity: msg.velocity ?? 0,
326→            event: msg.event,
327→            timestampMs: msg.timestampMs ?? Date.now(),
328→          });
329→
330→          if (!roomSession.midiFlushTimer) {
331→            roomSession.midiFlushTimer = setTimeout(() => {
332→              roomSession.midiFlushTimer = null;
333→              flushMidiToGemini(roomSession);
334→            }, 2000);
335→          }
336→        }
337→      } catch {}
338→    });
339→
340→    ws.on("close", () => {
341→      console.log(`[${APP_NAME}] MIDI bridge disconnected from room "${room}"`);
342→      if (roomSession.midiFlushTimer) {
343→        clearTimeout(roomSession.midiFlushTimer);
344→        roomSession.midiFlushTimer = null;
345→        flushMidiToGemini(roomSession);
346→      }
347→    });
348→  });
349→
350→  return server;
351→}
352→
353→// =========================================================================
354→// WebSocket handler — Gemini Live session (callback-based API)
355→// =========================================================================
356→
357→function randomHex(bytes: number): string {
358→  const arr = new Uint8Array(bytes);
359→  require("crypto").randomFillSync(arr);
360→  return Buffer.from(arr).toString("hex");
361→}
362→
363→async function* wsMessages(
364→  ws: WebSocket
365→): AsyncGenerator<Buffer | string, void, undefined> {
366→  const queue: (Buffer | string)[] = [];
367→  let resolve: (() => void) | null = null;
368→  let done = false;
369→
370→  ws.on("message", (data: Buffer | string) => {
371→    queue.push(data);
372→    if (resolve) {
373→      resolve();
374→      resolve = null;
375→    }
376→  });
377→
378→  ws.on("close", () => {
379→    done = true;
380→    if (resolve) {
381→      resolve();
382→      resolve = null;
383→    }
384→  });
385→
386→  ws.on("error", () => {
387→    done = true;
388→    if (resolve) {
389→      resolve();
390→      resolve = null;
391→    }
392→  });
393→
394→  while (true) {
395→    if (queue.length > 0) {
396→      yield queue.shift()!;
397→    } else if (done) {
398→      return;
399→    } else {
400→      await new Promise<void>((r) => {
401→        resolve = r;
402→      });
403→    }
404→  }
405→}
406→
407→async function handleWebSocket(ws: WebSocket) {
408→  const apiKey = process.env.GOOGLE_API_KEY ?? process.env.GEMINI_API_KEY;
409→  if (!apiKey) {
410→    ws.send(JSON.stringify({ type: "error", message: "No API key configured" }));
411→    ws.close();
412→    return;
413→  }
414→
415→  process.env.GOOGLE_API_KEY = apiKey;
416→
417→  const client = new GoogleGenAI({ apiKey });
418→  const sessionId = randomHex(4);
419→  const roomCode = generateRoomCode();
420→  let closed = false;
421→
422→  // Per-session state
423→  let cameraEnabled = true;
424→  let bothHandsDetected = false;
425→  let detectedHandCount = 0;
426→
427→  // Transcription buffers (gated on user speech)
428→  let bufInput = "";
429→  let bufOutput = "";
430→  let turnHasUserSpeech = false;
431→  const pendingAudioChunks: Buffer[] = [];
432→
433→  console.log(`[${APP_NAME}] Client connected: ${sessionId}, room: ${roomCode}`);
434→
435→  const liveConfig: Record<string, unknown> = {
436→    response_modalities: ["AUDIO"],
437→    system_instruction: STORYTELLER_INSTRUCTION,
438→    speech_config: {
439→      voice_config: {
440→        prebuilt_voice_config: { voice_name: "Puck" },
441→      },
442→    },
443→    input_audio_transcription: {},
444→    output_audio_transcription: {},
445→    realtime_input_config: {
446→      automatic_activity_detection: {
447→        disabled: false,
448→        silence_duration_ms: 1000,
449→      },
450→    },
451→    tools: buildToolDeclarations(),
452→  };
453→
454→  try {
455→    const session = await client.live.connect({
456→      model: LIVE_MODEL,
457→      config: liveConfig as any,
458→      callbacks: {
459→        onopen: () => {
460→          console.log(`[${APP_NAME}] Gemini Live session opened: ${sessionId}, room: ${roomCode}`);
461→          // Register room so remote cameras and MIDI bridges can join
462→          rooms.set(roomCode, {
463→            sendRealtimeInput: (input: any) => session.sendRealtimeInput(input),
464→            sendClientContent: (content: any) => session.sendClientContent(content),
465→            primaryWs: ws,
466→            midiBuffer: [],
467→            midiFlushTimer: null,
468→            cameraEnabled,
469→            bothHandsDetected,
470→            detectedHandCount,
471→          });
472→          // Send room code to primary client
473→          ws.send(JSON.stringify({ type: "room_code", room: roomCode }));
474→        },
475→        onmessage: (msg: any) => {
476→          if (closed) return;
477→
478→          try {
479→            // Helper: send to primary + all spectators
480→            const sendAll = (data: Buffer | string, binary = false) => {
481→              if (binary) {
482→                ws.send(data, { binary: true });
483→              } else {
484→                ws.send(data);
485→              }
486→              broadcast(data, binary);
487→            };
488→
489→            // Audio data from model turn
490→            if (msg.serverContent?.modelTurn?.parts) {
491→              for (const part of msg.serverContent.modelTurn.parts) {
492→                if (part.inlineData?.data) {
493→                  const audioBuffer = Buffer.from(part.inlineData.data, "base64");
494→                  if (turnHasUserSpeech) {
495→                    sendAll(audioBuffer, true);
496→                  } else {
497→                    pendingAudioChunks.push(audioBuffer);
498→                  }
499→                }
500→                if (part.text) {
501→                  const text = part.text.trim();
502→                  if (text) {
503→                    bufOutput = text;
504→                  }
505→                }
506→              }
507→            }
508→
509→            // Input transcription (user speech)
510→            if (msg.serverContent?.inputTranscription?.text) {
511→              const text = msg.serverContent.inputTranscription.text.trim();
512→              if (text) {
513→                bufInput = text;
514→                turnHasUserSpeech = true;
515→                // Flush pending audio now that we know user spoke
516→                while (pendingAudioChunks.length > 0) {
517→                  sendAll(pendingAudioChunks.shift()!, true);
518→                }
519→              }
520→            }
521→
522→            // Output transcription
523→            if (msg.serverContent?.outputTranscription?.text) {
524→              const text = msg.serverContent.outputTranscription.text.trim();
525→              if (text) {
526→                bufOutput = text;
527→              }
528→            }
529→
530→            // Tool calls from Gemini
531→            if (msg.toolCall?.functionCalls) {
532→              for (const fc of msg.toolCall.functionCalls) {
533→                const args = (fc.args ?? {}) as Record<string, unknown>;
534→
535→                // Send visual event to frontend
536→                const visualEvent = toolCallToVisualEvent(fc.name!, args);
537→                if (visualEvent) {
538→                  sendAll(JSON.stringify(visualEvent));
539→                }
540→
541→                // Send tool_call notification to frontend
542→                sendAll(
543→                  JSON.stringify({
544→                    type: "tool_call",
545→                    name: fc.name,
546→                    args,
547→                  })
548→                );
549→
550→                // Execute tool locally
551→                const result = executeToolLocally(fc.name!, args);
552→
553→                // Send tool_result to frontend
554→                sendAll(
555→                  JSON.stringify({
556→                    type: "tool_result",
557→                    name: fc.name,
558→                    result,
559→                  })
560→                );
561→
562→                // Send function response back to Gemini
563→                session.sendToolResponse({
564→                  functionResponses: [
565→                    {
566→                      name: fc.name!,
567→                      response: result,
568→                      id: fc.id,
569→                    },
570→                  ],
571→                });
572→              }
573→            }
574→
575→            // Turn complete
576→            if (msg.serverContent?.turnComplete) {
577→              if (turnHasUserSpeech && bufInput) {
578→                sendAll(
579→                  JSON.stringify({ type: "input_transcript", text: bufInput })
580→                );
581→                bufInput = "";
582→              }
583→              if (turnHasUserSpeech && bufOutput) {
584→                sendAll(
585→                  JSON.stringify({ type: "output_transcript", text: bufOutput })
586→                );
587→                bufOutput = "";
588→              }
589→              pendingAudioChunks.length = 0;
590→              if (turnHasUserSpeech) {
591→                sendAll(JSON.stringify({ type: "turn_complete" }));
592→              }
593→              turnHasUserSpeech = false;
594→            }
595→
596→            // Interrupted
597→            if (msg.serverContent?.interrupted) {
598→              if (turnHasUserSpeech && bufInput) {
599→                sendAll(
600→                  JSON.stringify({ type: "input_transcript", text: bufInput })
601→                );
602→                bufInput = "";
603→              }
604→              if (turnHasUserSpeech && bufOutput) {
605→                sendAll(
606→                  JSON.stringify({ type: "output_transcript", text: bufOutput })
607→                );
608→                bufOutput = "";
609→              }
610→              pendingAudioChunks.length = 0;
611→              if (turnHasUserSpeech) {
612→                sendAll(JSON.stringify({ type: "interrupted" }));
613→              }
614→              turnHasUserSpeech = false;
615→            }
616→          } catch (e: any) {
617→            if (!closed) {
618→              console.log(`[${APP_NAME}] onmessage error:`, e?.message);
619→            }
620→          }
621→        },
622→        onerror: (e: any) => {
623→          if (!closed) {
624→            console.log(`[${APP_NAME}] Gemini Live error:`, e?.message ?? e);
625→          }
626→        },
627→        onclose: () => {
628→          console.log(`[${APP_NAME}] Gemini Live session closed: ${sessionId}`);
629→          closed = true;
630→          try { ws.close(); } catch {}
631→        },
632→      },
633→    });
634→
635→    // ---------------------------------------------------------------
636→    // Receive from browser client, forward to Gemini
637→    // ---------------------------------------------------------------
638→    try {
639→      for await (const rawMsg of wsMessages(ws)) {
640→        if (closed) break;
641→
642→        // Binary = PCM audio at 16kHz
643→        if (rawMsg instanceof Buffer || rawMsg instanceof ArrayBuffer) {
644→          const data =
645→            rawMsg instanceof ArrayBuffer
646→              ? new Uint8Array(rawMsg)
647→              : rawMsg;
648→          session.sendRealtimeInput({
649→            audio: {
650→              data: Buffer.from(data).toString("base64"),
651→              mimeType: "audio/pcm;rate=16000",
652→            },
653→          });
654→        } else if (typeof rawMsg === "string") {
655→          const msg = JSON.parse(rawMsg);
656→          const msgType = msg.type;
657→
658→          if (msgType === "video_frame") {
659→            const frameBytes = Buffer.from(msg.data, "base64");
660→            session.sendRealtimeInput({
661→              media: {
662→                data: frameBytes.toString("base64"),
663→                mimeType: "image/jpeg",
664→              },
665→            });
666→          } else if (msgType === "text") {
667→            session.sendClientContent({
668→              turns: {
669→                role: "user",
670→                parts: [{ text: msg.content }],
671→              },
672→              turnComplete: true,
673→            });
674→          } else if (msgType === "midi_snapshot") {
675→            const summary = describeMidiSnapshot(
676→              msg,
677→              cameraEnabled,
678→              bothHandsDetected,
679→              detectedHandCount
680→            );
681→            if (summary) {
682→              session.sendClientContent({
683→                turns: {
684→                  role: "user",
685→                  parts: [{ text: summary }],
686→                },
687→                turnComplete: true,
688→              });
689→            }
690→          } else if (msgType === "set_mode") {
691→            // Single agent — mode is always storyteller
692→          } else if (msgType === "camera_state") {
693→            cameraEnabled = Boolean(msg.enabled);
694→            if (!cameraEnabled) {
695→              bothHandsDetected = false;
696→              detectedHandCount = 0;
697→            }
698→            const rs = rooms.get(roomCode);
699→            if (rs) { rs.cameraEnabled = cameraEnabled; rs.bothHandsDetected = bothHandsDetected; rs.detectedHandCount = detectedHandCount; }
700→          } else if (msgType === "hand_state") {
701→            detectedHandCount = parseInt(msg.detected_count ?? "0", 10);
702→            bothHandsDetected = Boolean(msg.both_hands_detected);
703→            const rs = rooms.get(roomCode);
704→            if (rs) { rs.bothHandsDetected = bothHandsDetected; rs.detectedHandCount = detectedHandCount; }
705→          } else if (msgType === "midi_event") {
706→            // Frontend uses raw MIDI events for UI rendering; snapshots go to agent
707→          } else if (msgType === "close") {
708→            break;
709→          }
710→        }
711→      }
712→    } catch (e: any) {
713→      if (!closed) console.log(`[${APP_NAME}] receive error:`, e?.message);
714→    }
715→
716→    closed = true;
717→  } catch (e: any) {
718→    console.error(`[${APP_NAME}] WebSocket error:`, e);
719→    try {
720→      ws.send(JSON.stringify({ type: "error", message: String(e) }));
721→    } catch {}
722→  } finally {
723→    const rs = rooms.get(roomCode);
724→    if (rs?.midiFlushTimer) clearTimeout(rs.midiFlushTimer);
725→    rooms.delete(roomCode);
726→    console.log(`[${APP_NAME}] Client disconnected: ${sessionId}, room ${roomCode} removed`);
727→    try {
728→      ws.close();
729→    } catch {}
730→  }
731→}
