 995→function updateScore() {
 996→  var nowMs = Date.now();
 997→  var recentHistory = noteHistory.filter(function(n) { return nowMs - n.startMs < 8000; });
 998→  if (recentHistory.length === 0) return;
 999→
1000→  var recentVelocities = recentHistory.slice(-12).map(function(n) { return n.velocity; });
1001→  var mean = recentVelocities.reduce(function(a, b) { return a + b; }, 0) / recentVelocities.length;
1002→  var variance = recentVelocities.reduce(function(a, v) { return a + Math.pow(v - mean, 2); }, 0) / recentVelocities.length;
1003→  var deviation = Math.sqrt(variance);
1004→  var evennessScore = Math.max(0, Math.min(100, 100 - deviation * 1.5));
1005→  if (recentVelocities.length >= 12 && deviation < 8) evenStreakCount += 1;
1006→  else evenStreakCount = 0;
1007→  if (evenStreakCount >= 3 && !earnedBadges.has('even_triad')) {
1008→    awardBadge('even_triad');
1009→    if (ws && ws.readyState === WebSocket.OPEN) {
1010→      ws.send(JSON.stringify({
1011→        type: 'text',
1012→        content: '[System: user achieved even_triad — dynamics evenness confirmed by 3 consecutive low-deviation chords]'
1013→      }));
1014→    }
1015→  }
1016→
1017→  var bpm = parseInt(bpmSlider.value, 10) || 90;
1018→  var beatIntervalMs = 60000 / bpm;
1019→  var recentOnsets = onsets.filter(function(t) { return nowMs - t < 10000; });
1020→  var rhythmScore = 60;
1021→  if (recentOnsets.length >= 3) {
1022→    var tolerance = beatIntervalMs * 0.15;
1023→    var onBeat = 0;
1024→    for (var r = 0; r < recentOnsets.length; r++) {
1025→      var nearest = Math.round(recentOnsets[r] / beatIntervalMs) * beatIntervalMs;
1026→      if (Math.abs(recentOnsets[r] - nearest) < tolerance) onBeat++;
1027→    }
1028→    rhythmScore = (onBeat / recentOnsets.length) * 100;
1029→  }
1030→
1031→  var raw = evennessScore * 0.65 + rhythmScore * 0.35;
1032→  scoreHistory.push(raw);
1033→  if (scoreHistory.length > 60) scoreHistory.shift();
1034→
1035→  var slice = scoreHistory.slice(-10);
1036→  var smoothed = slice.reduce(function(a, b) { return a + b; }, 0) / slice.length;
1037→  currentScore = Math.round(smoothed);
1038→
1039→  var el = document.getElementById('scoreNumber');
1040→  el.textContent = currentScore;
1041→  el.className = 'score-number' + (currentScore >= 70 ? ' high' : '');
1042→
1043→  var trend = document.getElementById('scoreTrend');
1044→  if (scoreHistory.length > 10) {
1045→    var oldSlice = scoreHistory.slice(-20, -10);
1046→    if (oldSlice.length > 0) {
1047→      var oldAvg = oldSlice.reduce(function(a, b) { return a + b; }, 0) / oldSlice.length;
1048→      var newAvg = smoothed;
1049→      if (newAvg > oldAvg + 3) { trend.textContent = '\u2191'; trend.className = 'score-trend up'; }
1050→      else if (newAvg < oldAvg - 3) { trend.textContent = '\u2193'; trend.className = 'score-trend down'; }
1051→      else { trend.textContent = ''; }
1052→    }
1053→  }
1054→}
