1208→function drawHandOverlay() {
1209→  var canvas = document.getElementById('handOverlay');
1210→  var video = document.getElementById('cameraVideo');
1211→  if (!canvas || !video) return;
1212→
1213→  var rect = video.getBoundingClientRect();
1214→  var dpr = window.devicePixelRatio || 1;
1215→  var width = Math.max(1, Math.round(rect.width * dpr));
1216→  var height = Math.max(1, Math.round(rect.height * dpr));
1217→  if (canvas.width !== width || canvas.height !== height) {
1218→    canvas.width = width;
1219→    canvas.height = height;
1220→  }
1221→
1222→  var ctx = canvas.getContext('2d');
1223→  ctx.setTransform(dpr, 0, 0, dpr, 0, 0);
1224→  ctx.clearRect(0, 0, rect.width, rect.height);
1225→
1226→  if (!cameraEnabled || !handLandmarks.length) return;
1227→
1228→  handLandmarks.forEach(function(points, handIndex) {
1229→    var lineColor = handIndex === 0 ? 'rgba(96,165,250,0.92)' : 'rgba(251,191,36,0.92)';
1230→    var jointColor = handIndex === 0 ? 'rgba(191,219,254,0.98)' : 'rgba(254,240,138,0.98)';
1231→    ctx.lineWidth = 2.2;
1232→    ctx.strokeStyle = lineColor;
1233→    HAND_CONNECTIONS.forEach(function(pair) {
1234→      var a = points[pair[0]];
1235→      var b = points[pair[1]];
1236→      if (!a || !b) return;
1237→      ctx.beginPath();
1238→      ctx.moveTo(a.x * rect.width, a.y * rect.height);
1239→      ctx.lineTo(b.x * rect.width, b.y * rect.height);
1240→      ctx.stroke();
1241→    });
1242→    points.forEach(function(point, idx) {
1243→      ctx.beginPath();
1244→      ctx.fillStyle = jointColor;
1245→      ctx.arc(point.x * rect.width, point.y * rect.height, idx === 0 ? 4.5 : 3, 0, Math.PI * 2);
1246→      ctx.fill();
1247→    });
1248→  });
1249→}
