1267→    select.innerHTML = '';
1268→    if (!inputs.length) {
1269→      select.innerHTML = '<option value="">No MIDI input found</option>';
1270→      if (midiInput) midiInput.onmidimessage = null;
1271→      midiInput = null;
1272→      updateMidiStatus('No MIDI input found');
1273→      return;
1274→    }
1275→
1276→    inputs.forEach(function(input) {
1277→      var option = document.createElement('option');
1278→      option.value = input.id;
1279→      option.textContent = input.name || 'MIDI Input';
1280→      select.appendChild(option);
1281→    });
1282→
1283→    if (!midiInput || !midiAccess.inputs.has(midiInput.id)) {
1284→      setMidiInput(inputs[0].id);
1285→    } else {
1286→      select.value = midiInput.id;
1287→      updateMidiStatus('MIDI: ' + (midiInput.name || 'Connected'));
1288→    }
1289→  } catch (err) {
1290→    var name = err && err.name ? err.name : 'Error';
1291→    if (name === 'NotAllowedError' || name === 'SecurityError') {
1292→      updateMidiStatus('MIDI permission blocked');
1293→    } else {
1294→      updateMidiStatus('MIDI error: ' + name);
1295→    }
1296→    console.error('Failed to refresh MIDI inputs', err);
1297→  }
1298→}
