1300→function setMidiInput(inputId) {
1301→  if (!midiAccess) return;
1302→  if (midiInput) midiInput.onmidimessage = null;
1303→  midiInput = inputId ? midiAccess.inputs.get(inputId) : null;
1304→  if (midiInput) {
1305→    midiInput.onmidimessage = handleMidiMessage;
1306→    document.getElementById('midiInputSelect').value = midiInput.id;
1307→    updateMidiStatus('MIDI: ' + (midiInput.name || 'Connected'));
1308→  } else {
1309→    updateMidiStatus('MIDI not connected');
1310→  }
1311→}
