1313→function handleMidiMessage(event) {
1314→  var data = event.data;
1315→  if (!data || data.length < 2) return;
1316→
1317→  var status = data[0];
1318→  var command = status & 0xf0;
1319→  var channel = status & 0x0f;
1320→  var data1 = data[1];
1321→  var data2 = data.length > 2 ? data[2] : 0;
1322→  var nowMs = Date.now();
1323→
1324→  if (command === 0x90 && data2 > 0) {
1325→    handleNoteOn(data1, data2, nowMs);
1326→    sendMidiEvent({ event: 'noteOn', note: data1, velocity: data2, channel: channel, timestampMs: nowMs });
1327→  } else if (command === 0x80 || (command === 0x90 && data2 === 0)) {
1328→    handleNoteOff(data1, nowMs);
1329→    sendMidiEvent({ event: 'noteOff', note: data1, velocity: data2, channel: channel, timestampMs: nowMs });
1330→  } else if (command === 0xb0) {
1331→    handleControlChange(data1, data2, nowMs);
1332→    sendMidiEvent({ event: 'controlChange', controller: data1, value: data2, channel: channel, timestampMs: nowMs });
1333→  }
1334→}
1335→
1336→function handleNoteOn(note, velocity, nowMs) {
1337→  activeNotes.set(note, { note: note, velocity: velocity, timestamp: nowMs });
1338→  fingerDownNotes.add(note);
1339→  pedalSustainedNotes.delete(note);
1340→  noteHistory.push({ note: note, velocity: velocity, startMs: nowMs, endMs: 0, fingerDurationMs: 0 });
1341→  if (noteHistory.length > 500) noteHistory.splice(0, noteHistory.length - 500);
1342→  recentMidiNotes.push({ note: note, velocity: velocity, timestampMs: nowMs });
1343→  if (recentMidiNotes.length > 64) recentMidiNotes.splice(0, recentMidiNotes.length - 64);
1344→  onsets.push(nowMs);
1345→  while (onsets.length && nowMs - onsets[0] > 30000) onsets.shift();
1346→  scheduleMidiSnapshot();
1347→}
1348→
1349→function handleNoteOff(note, nowMs) {
1350→  fingerDownNotes.delete(note);
1351→
1352→  for (var i = noteHistory.length - 1; i >= 0; i--) {
1353→    var entry = noteHistory[i];
1354→    if (entry.note === note && entry.endMs === 0) {
1355→      entry.fingerDurationMs = Math.max(0, nowMs - entry.startMs);
1356→      if (pedalDown) {
1357→        pedalSustainedNotes.add(note);
1358→      } else {
1359→        entry.endMs = nowMs;
1360→        activeNotes.delete(note);
1361→      }
1362→      break;
1363→    }
1364→  }
1365→
1366→  if (!pedalDown) {
1367→    pedalSustainedNotes.delete(note);
1368→    activeNotes.delete(note);
1369→  }
1370→
1371→  scheduleMidiSnapshot();
1372→}
1373→
1374→function handleControlChange(controller, value, nowMs) {
1375→  if (controller !== 64) return;
1376→  var wasDown = pedalDown;
1377→  pedalDown = value >= 64;
1378→  updatePedalStatus();
1379→
1380→  if (wasDown && !pedalDown) {
1381→    pedalSustainedNotes.forEach(function(note) {
1382→      activeNotes.delete(note);
1383→      for (var i = noteHistory.length - 1; i >= 0; i--) {
1384→        var entry = noteHistory[i];
1385→        if (entry.note === note && entry.endMs === 0) {
1386→          entry.endMs = nowMs;
1387→          break;
1388→        }
1389→      }
1390→    });
1391→    pedalSustainedNotes.clear();
1392→  }
1393→
1394→  scheduleMidiSnapshot();
1395→}
1396→
1397→function sendMidiEvent(payload) {
1398→  if (!ws || ws.readyState !== WebSocket.OPEN) return;
1399→  ws.send(JSON.stringify({
1400→    type: 'midi_event',
1401→    event: payload.event,
1402→    note: payload.note,
1403→    velocity: payload.velocity,
1404→    controller: payload.controller,
1405→    value: payload.value,
1406→    channel: payload.channel,
1407→    timestampMs: payload.timestampMs
1408→  }));
1409→}
1410→
1411→function scheduleMidiSnapshot() {
1412→  if (midiSnapshotTimer) clearTimeout(midiSnapshotTimer);
1413→  midiSnapshotTimer = setTimeout(function() {
1414→    sendMidiSnapshot(false);
1415→  }, 250);
1416→}
1417→
1418→function sendMidiSnapshot(force) {
1419→  if (!ws || ws.readyState !== WebSocket.OPEN) return;
1420→  var nowMs = Date.now();
1421→
1422→  var activePayload = Array.from(activeNotes.values()).map(function(note) {
1423→    return { note: note.note, velocity: note.velocity };
1424→  });
1425→  var recentPayload = recentMidiNotes
1426→    .filter(function(note) { return nowMs - note.timestampMs < 2500; })
1427→    .slice(-8)
1428→    .map(function(note) { return { note: note.note, velocity: note.velocity }; });
1429→
1430→  var hasPerformanceSignal = activePayload.length > 0 || recentPayload.length > 0 || pedalDown;
1431→  if (!hasPerformanceSignal) return;
1432→  if (!force && nowMs - lastMidiSnapshotAt < 1200) return;
1433→  lastMidiSnapshotAt = nowMs;
1434→
1435→  ws.send(JSON.stringify({
1436→    type: 'midi_snapshot',
1437→    active_notes: activePayload,
1438→    recent_notes: recentPayload,
1439→    detected_techniques: detectTechniques(),
1440→    pedal_down: pedalDown,
1441→    bpm: parseInt(bpmSlider.value, 10) || 90,
1442→    score: currentScore
1443→  }));
1444→}
