.right-col { display: flex; flex-direction: column; gap: 12px; }

/* Story Scene Card */
.scene-card {
  position: relative;
  min-height: 120px;
  border-radius: 12px;
  border: 1px solid var(--border);
  overflow: hidden;
  transition: all 0.8s ease;
}
