699→function buildKeyboard() {
700→  var keys = [];
701→  var whiteIdx = 0;
702→  for (var i = 0; i < TOTAL_KEYS; i++) {
703→    var midi = FIRST_MIDI + i;
704→    var noteInOctave = midi % 12;
705→    var isBlack = BLACK_KEY_PATTERN[noteInOctave];
706→    keys.push({ midi: midi, isBlack: isBlack, whiteIndex: isBlack ? whiteIdx - 1 : whiteIdx });
707→    if (!isBlack) whiteIdx++;
708→  }
709→  return keys;
710→}
711→
712→function noteName(note) {
713→  return NOTE_NAMES[note % 12] + (Math.floor(note / 12) - 1);
714→}
715→
716→function detectTechniques() {
717→  var notes = recentMidiNotes.slice(-12).map(function(item) { return item.note; });
718→  var labels = [];
719→  if (notes.length < 2) return labels;
720→
721→  var ascendingRun = 1;
722→  var descendingRun = 1;
723→  var repeatedRun = 1;
724→  var arpeggioRun = 1;
725→
726→  function pushUnique(label) {
727→    if (labels.indexOf(label) === -1) labels.push(label);
728→  }
729→
730→  for (var i = 1; i < notes.length; i++) {
731→    var diff = notes[i] - notes[i - 1];
732→    var absDiff = Math.abs(diff);
733→
734→    if (diff === 1 || diff === 2) ascendingRun += 1;
735→    else ascendingRun = 1;
736→
737→    if (diff === -1 || diff === -2) descendingRun += 1;
738→    else descendingRun = 1;
739→
740→    if (ascendingRun >= 4) pushUnique('scale_run_ascending');
741→    if (descendingRun >= 4) pushUnique('scale_run_descending');
742→
743→    if (notes[i] === notes[i - 1]) repeatedRun += 1;
744→    else repeatedRun = 1;
745→
746→    if (repeatedRun >= 3) {
747→      pushUnique('repeated_note(' + noteName(notes[i]) + 'x' + repeatedRun + ')');
748→    }
749→
750→    if (absDiff === 3 || absDiff === 4) arpeggioRun += 1;
751→    else arpeggioRun = 1;
752→
753→    if (arpeggioRun >= 3) pushUnique('arpeggio');
754→    if (absDiff > 7) pushUnique('wide_leap');
755→  }
756→
757→  return labels;
758→}
