760→function dynamicsRgb(velocity) {
761→  if (velocity <= DYNAMICS_COLORS[0].vel) return DYNAMICS_COLORS[0];
762→  for (var i = 1; i < DYNAMICS_COLORS.length; i++) {
763→    if (velocity <= DYNAMICS_COLORS[i].vel) {
764→      var lo = DYNAMICS_COLORS[i - 1];
765→      var hi = DYNAMICS_COLORS[i];
766→      var t = (velocity - lo.vel) / (hi.vel - lo.vel);
767→      return {
768→        r: Math.round(lo.r + (hi.r - lo.r) * t),
769→        g: Math.round(lo.g + (hi.g - lo.g) * t),
770→        b: Math.round(lo.b + (hi.b - lo.b) * t)
771→      };
772→    }
773→  }
774→  return DYNAMICS_COLORS[DYNAMICS_COLORS.length - 1];
775→}
