777→function dynamicsColor(velocity, alpha) {
778→  var c = dynamicsRgb(velocity);
779→  if (alpha == null) return 'rgb(' + c.r + ',' + c.g + ',' + c.b + ')';
780→  return 'rgba(' + c.r + ',' + c.g + ',' + c.b + ',' + alpha + ')';
781→}
