783→function darkenedColor(velocity, factor, alpha) {
784→  var c = dynamicsRgb(velocity);
785→  var r = Math.round(c.r * factor);
786→  var g = Math.round(c.g * factor);
787→  var b = Math.round(c.b * factor);
788→  if (alpha == null) return 'rgb(' + r + ',' + g + ',' + b + ')';
789→  return 'rgba(' + r + ',' + g + ',' + b + ',' + alpha + ')';
790→}
