  ctx.fillRect(0, dynamicsY, W, dynamicsH);
  ctx.strokeStyle = 'rgba(255,255,255,0.1)';
  ctx.lineWidth = 1;
  ctx.beginPath();
  ctx.moveTo(0, dynamicsY);
  ctx.lineTo(W, dynamicsY);
  ctx.stroke();

  ctx.font = '9px DM Sans, sans-serif';
  DYNAMICS_LABELS.forEach(function(dl) {
    var y = dynamicsY + dynamicsH - (dl.vel / 127) * dynamicsH;
    ctx.strokeStyle = dynamicsColor(dl.vel, 0.28);
    ctx.lineWidth = 0.5;
    ctx.beginPath();
    ctx.moveTo(0, y);
    ctx.lineTo(W, y);
    ctx.stroke();
    ctx.fillStyle = dynamicsColor(dl.vel, 0.4);
    ctx.fillText(dl.label, 3, y - 2);
  });

  function drawBars(blackOnly) {
    activeNotes.forEach(function(note, midi) {
      var keyInfo = KEY_BY_MIDI.get(midi);
      if (!keyInfo || keyInfo.isBlack !== blackOnly) return;
      var barH = (note.velocity / 127) * (dynamicsH - 4);
      var barX = keyInfo.isBlack
