      var barW = keyInfo.isBlack ? blackKeyW : whiteKeyW - 2;
      var color = fingerDownNotes.has(midi) ? dynamicsColor(note.velocity) : darkenedColor(note.velocity, 0.5);
      if (keyInfo.isBlack) {
        ctx.fillStyle = '#111118';
        ctx.fillRect(barX, dynamicsY + 1, barW, dynamicsH - 2);
      }
      ctx.fillStyle = color;
      ctx.fillRect(barX, dynamicsY + dynamicsH - barH - 2, barW, barH);
    });
  }

  drawBars(false);
  drawBars(true);
}

