function renderDeviceList() {
  var container = document.getElementById('deviceListItems');
  if (!container) return;
  container.textContent = '';
  var countEl = document.getElementById('deviceCount');
  if (countEl) countEl.textContent = deviceList.length + (deviceList.length === 1 ? ' device' : ' devices');

  deviceList.forEach(function(dev) {
    var item = document.createElement('div');
    item.className = 'device-item' + (dev.isPrimary ? ' is-primary' : '');

    var icon = document.createElement('span');
    icon.className = 'device-icon';
    icon.textContent = dev.deviceType === 'desktop' ? '\uD83D\uDCBB' : dev.deviceType === 'tablet' ? '\uD83D\uDCF1' : dev.deviceType === 'phone' ? '\uD83D\uDCF7' : '\uD83D\uDD32';
    item.appendChild(icon);

    var info = document.createElement('div');
    info.className = 'device-info';
    var nameEl = document.createElement('div');
    nameEl.className = 'device-name';
    nameEl.textContent = dev.name;
    info.appendChild(nameEl);
    var typeEl = document.createElement('div');
    typeEl.className = 'device-type-label';
    typeEl.textContent = dev.deviceType;
    info.appendChild(typeEl);
    item.appendChild(info);

    var roles = document.createElement('div');
    roles.className = 'device-roles';

    ['mic', 'camera', 'midi'].forEach(function(role) {
      var pill = document.createElement('span');
      var label = role === 'mic' ? 'MIC' : role === 'camera' ? 'CAM' : 'MIDI';
      var pillClass = role === 'mic' ? 'mic-pill' : role === 'camera' ? 'cam-pill' : 'midi-pill';
      pill.className = 'role-pill ' + pillClass + (dev.roles[role] ? ' active' : '');
      pill.textContent = label;
      pill.onclick = function() {
        if (!isPrimaryDevice || !ws || ws.readyState !== WebSocket.OPEN) return;
        ws.send(JSON.stringify({
          type: 'set_device_role',
          deviceId: dev.id,
          role: role,
          enabled: !dev.roles[role]
        }));
      };
      roles.appendChild(pill);
    });

    item.appendChild(roles);
    container.appendChild(item);
  });
}

