function updateScore() {
  var nowMs = Date.now();
  var recentHistory = noteHistory.filter(function(n) { return nowMs - n.startMs < 8000; });
  if (recentHistory.length === 0) return;

  var recentVelocities = recentHistory.slice(-12).map(function(n) { return n.velocity; });
  var mean = recentVelocities.reduce(function(a, b) { return a + b; }, 0) / recentVelocities.length;
  var variance = recentVelocities.reduce(function(a, v) { return a + Math.pow(v - mean, 2); }, 0) / recentVelocities.length;
  var deviation = Math.sqrt(variance);
  var evennessScore = Math.max(0, Math.min(100, 100 - deviation * 1.5));
  if (recentVelocities.length >= 12 && deviation < 8) evenStreakCount += 1;
  else evenStreakCount = 0;
  if (evenStreakCount >= 3 && !earnedBadges.has('even_triad')) {
    awardBadge('even_triad');
    if (ws && ws.readyState === WebSocket.OPEN) {
      ws.send(JSON.stringify({
        type: 'text',
        content: '[System: user achieved even_triad — dynamics evenness confirmed by 3 consecutive low-deviation chords]'
      }));
    }
  }

  var bpm = parseInt(bpmSlider.value, 10) || 90;
  var beatIntervalMs = 60000 / bpm;
  var recentOnsets = onsets.filter(function(t) { return nowMs - t < 10000; });
  var rhythmScore = 60;
  if (recentOnsets.length >= 3) {
    var tolerance = beatIntervalMs * 0.15;
    var onBeat = 0;
    for (var r = 0; r < recentOnsets.length; r++) {
      var nearest = Math.round(recentOnsets[r] / beatIntervalMs) * beatIntervalMs;
      if (Math.abs(recentOnsets[r] - nearest) < tolerance) onBeat++;
    }
    rhythmScore = (onBeat / recentOnsets.length) * 100;
  }

  var raw = evennessScore * 0.65 + rhythmScore * 0.35;
  scoreHistory.push(raw);
  if (scoreHistory.length > 60) scoreHistory.shift();

  var slice = scoreHistory.slice(-10);
  var smoothed = slice.reduce(function(a, b) { return a + b; }, 0) / slice.length;
  currentScore = Math.round(smoothed);

  var el = document.getElementById('scoreNumber');
  el.textContent = currentScore;
  el.className = 'score-number' + (currentScore >= 70 ? ' high' : '');

  var trend = document.getElementById('scoreTrend');
  if (scoreHistory.length > 10) {
    var oldSlice = scoreHistory.slice(-20, -10);
    if (oldSlice.length > 0) {
      var oldAvg = oldSlice.reduce(function(a, b) { return a + b; }, 0) / oldSlice.length;
      var newAvg = smoothed;
      if (newAvg > oldAvg + 3) { trend.textContent = '\u2191'; trend.className = 'score-trend up'; }
      else if (newAvg < oldAvg - 3) { trend.textContent = '\u2193'; trend.className = 'score-trend down'; }
      else { trend.textContent = ''; }
    }
  }
}

function resetMidiState() {
  activeNotes.clear();
  fingerDownNotes.clear();
  pedalSustainedNotes.clear();

