// UI Updates for interleaved output features
// ============================================================================
function setScene(sceneId) {
  currentScene = sceneId;
  var scene = SCENES[sceneId];
  if (!scene) return;
  document.getElementById('sceneCard').setAttribute('data-scene', sceneId);
  document.getElementById('sceneChapter').textContent = scene.chapter;
  document.getElementById('sceneTitle').textContent = scene.title;
  document.getElementById('sceneDesc').textContent = scene.desc;
  document.getElementById('sceneIcon').textContent = scene.icon;
}

function setCoachingFocus(text) {
  document.getElementById('coachingText').textContent = text;
}

function awardBadge(badgeId) {
  if (earnedBadges.has(badgeId)) return;
  earnedBadges.add(badgeId);
  var info = ACHIEVEMENTS[badgeId];
  if (!info) return;

  // Add to badge shelf
  var area = document.getElementById('badgesArea');
  var empty = area.querySelector('.badges-empty');
  if (empty) empty.remove();
  var badge = document.createElement('div');
  badge.className = 'badge';
  badge.textContent = info.icon + ' ' + info.name;
  area.appendChild(badge);

  // Show popup notification
  var popup = document.createElement('div');
  popup.className = 'achievement-popup';
  var iconEl = document.createElement('div');
  iconEl.className = 'ach-icon';
  iconEl.textContent = info.icon;
  var textEl = document.createElement('div');
  var nameEl = document.createElement('div');
  nameEl.className = 'ach-name';
  nameEl.textContent = 'Achievement Unlocked: ' + info.name;
  var subEl = document.createElement('div');
  subEl.className = 'ach-sub';
  subEl.textContent = info.desc;
  textEl.appendChild(nameEl);
  textEl.appendChild(subEl);
  popup.appendChild(iconEl);
  popup.appendChild(textEl);
  document.body.appendChild(popup);
  setTimeout(function() { popup.remove(); }, 3500);
}

function advanceQuest(phase) {
  if (phase <= questPhase) return;
  questPhase = phase;
  var nodeIds = ['qn-opening', 'qn-assessment', 'qn-challenge', 'qn-mastery', 'qn-celebration'];
  var lineIds = ['ql-1', 'ql-2', 'ql-3', 'ql-4'];
  for (var i = 0; i < nodeIds.length; i++) {
    var node = document.getElementById(nodeIds[i]);
    node.className = 'quest-node';
    if (i < phase) node.classList.add('completed');
    else if (i === phase) node.classList.add('active');
  }
  for (var j = 0; j < lineIds.length; j++) {
    var line = document.getElementById(lineIds[j]);
    line.className = 'quest-line';
    if (j < phase) line.classList.add('completed');
  }
  if (phase >= 1 && !earnedBadges.has('first_note')) awardBadge('first_note');
}

function updateScore() {
  var nowMs = Date.now();
  var recentHistory = noteHistory.filter(function(n) { return nowMs - n.startMs < 8000; });
  if (recentHistory.length === 0) return;

  var recentVelocities = recentHistory.slice(-12).map(function(n) { return n.velocity; });
  var mean = recentVelocities.reduce(function(a, b) { return a + b; }, 0) / recentVelocities.length;
  var variance = recentVelocities.reduce(function(a, v) { return a + Math.pow(v - mean, 2); }, 0) / recentVelocities.length;
  var deviation = Math.sqrt(variance);
  var evennessScore = Math.max(0, Math.min(100, 100 - deviation * 1.5));
  if (recentVelocities.length >= 12 && deviation < 8) evenStreakCount += 1;
  else evenStreakCount = 0;
  if (evenStreakCount >= 3 && !earnedBadges.has('even_triad')) {
    awardBadge('even_triad');
    if (ws && ws.readyState === WebSocket.OPEN) {
      ws.send(JSON.stringify({
        type: 'text',
        content: '[System: user achieved even_triad — dynamics evenness confirmed by 3 consecutive low-deviation chords]'
      }));
    }
  }

  var bpm = parseInt(bpmSlider.value, 10) || 90;
  var beatIntervalMs = 60000 / bpm;
  var recentOnsets = onsets.filter(function(t) { return nowMs - t < 10000; });
  var rhythmScore = 60;
  if (recentOnsets.length >= 3) {
    var tolerance = beatIntervalMs * 0.15;
    var onBeat = 0;
    for (var r = 0; r < recentOnsets.length; r++) {
      var nearest = Math.round(recentOnsets[r] / beatIntervalMs) * beatIntervalMs;
      if (Math.abs(recentOnsets[r] - nearest) < tolerance) onBeat++;
    }
    rhythmScore = (onBeat / recentOnsets.length) * 100;
  }

  var raw = evennessScore * 0.65 + rhythmScore * 0.35;
  scoreHistory.push(raw);
  if (scoreHistory.length > 60) scoreHistory.shift();

  var slice = scoreHistory.slice(-10);
  var smoothed = slice.reduce(function(a, b) { return a + b; }, 0) / slice.length;
  currentScore = Math.round(smoothed);

  var el = document.getElementById('scoreNumber');
  el.textContent = currentScore;
  el.className = 'score-number' + (currentScore >= 70 ? ' high' : '');

  var trend = document.getElementById('scoreTrend');
  if (scoreHistory.length > 10) {
    var oldSlice = scoreHistory.slice(-20, -10);
    if (oldSlice.length > 0) {
      var oldAvg = oldSlice.reduce(function(a, b) { return a + b; }, 0) / oldSlice.length;
      var newAvg = smoothed;
      if (newAvg > oldAvg + 3) { trend.textContent = '\u2191'; trend.className = 'score-trend up'; }
      else if (newAvg < oldAvg - 3) { trend.textContent = '\u2193'; trend.className = 'score-trend down'; }
      else { trend.textContent = ''; }
    }
  }
}

